def verify(output: str):
    # Constraint checks
    constraints_satisfied = 0
    total_constraints = 5
    failed_constraints = []

    # Check 1: The string contains exactly 1 occurrence of the substring "2026"
    count_2026 = output.count("2026")
    if count_2026 == 1:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"Exactly 1 occurrence of '2026' (found {count_2026})")

    # Check 2: The string contains no occurrence of "000"
    if "000" not in output:
        constraints_satisfied += 1
    else:
        failed_constraints.append("No occurrence of '000'")

    # Check 3: The string must not start with '0'
    if output[0] != '0':
        constraints_satisfied += 1
    else:
        failed_constraints.append("Must not start with '0'")

    # Check 4: The string must end with an odd digit
    odd_digits = {'1', '3', '5', '7', '9'}
    if output[-1] in odd_digits:
        constraints_satisfied += 1
    else:
        failed_constraints.append("Must end with an odd digit")

    # Check 5: Total number of even digits (0,2,4,6,8) is exactly 10
    even_digits = {'0', '2', '4', '6', '8'}
    even_count = sum(1 for ch in output if ch in even_digits)
    if even_count == 10:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"Exactly 10 even digits (found {even_count})")

    # Calculate score
    score = constraints_satisfied / total_constraints

    # Determine validity
    is_valid = constraints_satisfied == total_constraints

    # Generate message
    if is_valid:
        message = "All constraints satisfied."
    else:
        message = f"Failed constraints: {', '.join(failed_constraints)}."

    return (is_valid, score, message)
